	// (GET /admin/v1/memory-index/status)
	AdminGetMemoryIndexStatus(c *gin.Context)
	// Trigger one episodic memory indexing cycle
	// (POST /admin/v1/memory-index/trigger)
	AdminTriggerMemoryIndex(c *gin.Context)
